import type { Context } from "@hushkey/howl";
import type { State } from "../../howl.config.ts";

export default function HomePage(ctx: Context<State>) {
  return <h1>Hello, {ctx.state.userContext?.id ?? "guest"}</h1>;
}

// pages/blog/[slug].tsx → /blog/:slug
export default function BlogPost(ctx: Context<State>) {
  const { slug } = ctx.params;
  return <article>Post: {slug}</article>;
}

// pages/[[name]].tsx — matches both / and /:name
export default function Greeting(ctx: Context<State>) {
  const { name } = ctx.params;
  return <h1>Hello, {name || "world"}!</h1>;
}

// pages/_layout.tsx — applies to all pages
export default function Layout({ Component }: { Component: () => JSX.Element }) {
  return (
    <>
      <nav class="navbar">
        <a href="/">Home</a>
        <a href="/docs">Docs</a>
      </nav>
      <main>
        <Component />
      </main>
    </>
  );
}

import { Howl } from "@hushkey/howl";

const app = new Howl();

app.layout("/", ({ Component }) => (
  <html><body>root<Component /></body></html>
));

app.layout("/foo", ({ Component }) => (
  <section>foo-shell<Component /></section>
));

// /foo gets BOTH the root layout AND the /foo layout wrapped around it.
app.route("/foo", { component: () => <p>foo-index</p> });

// Verb handlers also see the matching layouts when they call ctx.render().
app.get("/foo", (ctx) => ctx.render(<p>page</p>));

// pages/_app.tsx
import { Partial } from "@hushkey/howl/runtime";

export default function App({ Component }) {
  return (
    <html>
      <head>
        <meta charset="utf-8" />
        <title>My App</title>
        <link rel="stylesheet" href="/style.css" />
      </head>
      <body f-client-nav>
        <Partial name="main">
          <Component />
        </Partial>
      </body>
    </html>
  );
}

// /sign-in is reached during a partial nav. The Location header becomes
// /dashboard?howl-partial=true so the redirect target also renders as
// a partial.
app.post("/sign-in", (ctx) => ctx.redirect("/dashboard"));

// Existing query/hash are handled correctly:
ctx.redirect("/page?tab=home");   // → /page?tab=home&howl-partial=true
ctx.redirect("/page#section");    // → /page?howl-partial=true#section

// Linking to a file the browser will download or render natively.
// Howl detects the non-HTML Content-Type and does a full navigation.
<a href="/static/report.pdf">Download report</a>

// Anywhere in your app — Howl detects active state from the URL
<a href="/blog">Blog</a>
<a href="/blog/post-1">Post 1</a>

// Visiting /blog/post-1 produces:
//   <a href="/blog" data-ancestor="true" aria-current="true">Blog</a>
//   <a href="/blog/post-1" data-current="true" aria-current="page">Post 1</a>

/* Tailwind / vanilla — both work */
a[data-current] { color: var(--color-primary); font-weight: 600; }
a[data-ancestor] { color: var(--color-primary); opacity: 0.7; }

// pages/blog/[slug].tsx — ld+json metadata follows the partial swap
<script type="application/ld+json" id="article-schema">
  {JSON.stringify({
    "@context": "https://schema.org",
    "@type": "Article",
    headline: post.title,
    datePublished: post.publishedAt,
  })}
</script>
